TriggerOraclev10g.body:
BEGIN
    -- Asignar el próximo valor de la secuencia si el id es NULL
    IF :new.id IS NULL
    THEN
        :new.id := tkr_servicios_de_entidad_seq.NEXTVAL;
    END IF;

    -- Asignar la fecha de creación con el valor de SYSDATE
    :new.fecha_creacion := f_fecha_actual;
END;
